import React, { useEffect, useState } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { createChanson, getChanson, updateChanson, createChansonWithMusic, updateChansonWithMusic } from '../api/chansonService';
import { getAlbums } from '../api/albumService';

export default function ChansonForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [model, setModel] = useState({ titre: '', albumId: '', fichierAudio: null });
  const [albums, setAlbums] = useState([]);
  const [existingFile, setExistingFile] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    getAlbums().then((response) => setAlbums(response.data || [])).catch(() => setAlbums([]));
  }, []);

  useEffect(() => {
    if (id) {
      setLoading(true);
      getChanson(id)
        .then((response) => {
          const chanson = response.data || {};
          setModel({
            titre: chanson.titre || '',
            albumId: chanson.albumId || '',
            fichierAudio: null,
          });
          setExistingFile(chanson.fichierAudio || '');
        })
        .finally(() => setLoading(false));
    }
  }, [id]);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);

    if (model.fichierAudio) {
      const formData = new FormData();
      formData.append('titre', model.titre);
      formData.append('albumId', model.albumId);
      formData.append('music', model.fichierAudio);
      const op = id ? updateChansonWithMusic(id, formData) : createChansonWithMusic(formData);
      op.then(() => navigate('/chansons')).finally(() => setLoading(false));
      return;
    }

    const payload = {
      titre: model.titre,
      albumId: parseInt(model.albumId, 10) || null,
      fichierAudio: existingFile || null,
    };

    const op = id ? updateChanson(id, payload) : createChanson(payload);
    op.then(() => navigate('/chansons')).finally(() => setLoading(false));
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">{id ? 'Modifier' : 'Créer'} une chanson</h1>
          <p className="text-muted mb-0">Importer un titre audio et relier la chanson à un album.</p>
        </div>
        <Link className="btn btn-secondary" to="/chansons">
          Retour aux chansons
        </Link>
      </div>

      <form onSubmit={handleSubmit} className="card shadow-sm border-0 p-4">
        <div className="mb-3">
          <label className="form-label">Titre</label>
          <input
            className="form-control"
            value={model.titre}
            onChange={(e) => setModel({ ...model, titre: e.target.value })}
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">Album</label>
          <select
            className="form-select"
            value={model.albumId}
            onChange={(e) => setModel({ ...model, albumId: e.target.value })}
            required
          >
            <option value="">Sélectionnez un album</option>
            {albums.map((album) => (
              <option key={album.id} value={album.id}>
                {album.titre}
              </option>
            ))}
          </select>
        </div>

        {existingFile && (
          <div className="mb-3">
            <label className="form-label">Fichier audio actuel</label>
            <div>
              <audio controls className="w-100">
                <source src={`/uploads/musics/${existingFile}`} type="audio/mpeg" />
                Votre navigateur ne supporte pas l'audio.
              </audio>
            </div>
          </div>
        )}

        <div className="mb-3">
          <label className="form-label">Fichier audio</label>
          <input
            type="file"
            accept="audio/*"
            className="form-control"
            onChange={(e) => setModel({ ...model, fichierAudio: e.target.files[0] })}
          />
          <div className="form-text">Laisser vide pour conserver le fichier existant.</div>
        </div>

        <button className="btn btn-primary" type="submit" disabled={loading}>
          {loading ? 'Enregistrement...' : 'Sauvegarder'}
        </button>
      </form>
    </div>
  );
}
